def count_flops(layers: list) -> dict:
    per_layer_flops = []

    for layer in layers:
        ltype = layer['type']
        if ltype == 'linear':
            macs = layer['in'] * layer['out']
            flops = 2 * macs
        elif ltype == 'conv2d':
            macs = layer['in_c'] * layer['out_c'] * layer['k'] ** 2 * layer['h'] * layer['w']
            flops = 2 * macs
        elif ltype == 'attention':
            L, D = layer['seq_len'], layer['dim']
            macs = 4 * L * D * D + 2 * L * L * D
            flops = 2 * macs
        elif ltype in ('relu', 'layernorm', 'batchnorm'):
            flops = 0
        else:
            raise ValueError(f"Unknown layer type: {ltype!r}")
        per_layer_flops.append(flops)

    total_flops = sum(per_layer_flops)
    return {
        'total_flops': total_flops,
        'total_macs': total_flops // 2,
        'per_layer_flops': per_layer_flops
    }

